import{_ as t,o as r,c as o,ag as a}from"./chunks/framework.CxZWPeXl.js";const h=JSON.parse('{"title":"Prompt Management","description":"","frontmatter":{},"headers":[],"relativePath":"en/admin-prompts.md","filePath":"en/admin-prompts.md"}'),i={name:"en/admin-prompts.md"};function s(n,e,l,c,p,d){return r(),o("div",null,[...e[0]||(e[0]=[a('<h1 id="prompt-management" tabindex="-1">Prompt Management <a class="header-anchor" href="#prompt-management" aria-label="Permalink to &quot;Prompt Management&quot;">​</a></h1><blockquote><p>Control the core behavior of the AI, setting its mindset and evaluation standards.</p></blockquote><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>Prompts are the core instructions that drive the entire AI Coach platform. This feature allows administrators to adjust how the AI role-plays customers, defines reporting criteria, and applies system rules.</p><blockquote><p>Access is restricted to Administrators only.</p></blockquote><h2 id="interface-structure" tabindex="-1">Interface Structure <a class="header-anchor" href="#interface-structure" aria-label="Permalink to &quot;Interface Structure&quot;">​</a></h2><p>The management page is divided into two main sections:</p><ul><li><strong>Toolbar &amp; Filters (Top/Left)</strong>: <ul><li><strong>Company/Department Dropdown:</strong> Filter prompts that apply specifically to an organization (e.g., 台灣國泰人壽).</li><li><strong>Version Dropdown:</strong> Select the active prompt version you are working on (e.g., v1.0, v2.0 - Active).</li></ul></li><li><strong>List &amp; Editor</strong>: A panel displaying the list of specific Prompts and a large text editor for the prompt source code.</li></ul><hr><h2 id="prompt-card-details" tabindex="-1">Prompt Card Details <a class="header-anchor" href="#prompt-card-details" aria-label="Permalink to &quot;Prompt Card Details&quot;">​</a></h2><p>Each prompt card displays:</p><ul><li><strong>Name</strong>: A unique identifier within the system.</li><li><strong>Category</strong>: Classification of the prompt (e.g., System, Character, Judge, Auto-Suggestions).</li><li><strong>Description</strong>: A brief summary of its function.</li><li><strong>Status</strong>: Indicates whether the Prompt is part of the &quot;Active/In-Use&quot; version.</li></ul><p>The editor provides a large text area for administrators to securely type and update instructions directly.</p><hr><h2 id="variable-system" tabindex="-1">Variable System <a class="header-anchor" href="#variable-system" aria-label="Permalink to &quot;Variable System&quot;">​</a></h2><p>Within the Prompt content, you can utilize dynamic variables enclosed in curly braces <code>{...}</code> to instruct the system to automatically inject actual runtime data: For example:</p><ul><li><code>{question}</code>: The user&#39;s latest query or message.</li><li><code>{character_detail}</code>: The auto-generated customer persona background.</li><li><code>{conversation_history}</code>: The transcript of the chat up to the current instance.</li><li><code>{stage_description}</code>: Descriptions of the currently applicable sales stages.</li></ul><hr><h2 id="version-control" tabindex="-1">Version Control <a class="header-anchor" href="#version-control" aria-label="Permalink to &quot;Version Control&quot;">​</a></h2><p>The system permits you to safely edit and test Prompts without impacting live sessions:</p><ul><li><strong>Add Version</strong>: Duplicates all Prompts from the current version into a new draft.</li><li><strong>Save Changes</strong>: Edits are contained exclusively within the selected version.</li><li><strong>Publish</strong>: Promotes the draft version into the live production environment as the Active version. Note: Once published, the new version applies strictly to <em>new</em> practice sessions moving forward.</li></ul>',21)])])}const u=t(i,[["render",s]]);export{h as __pageData,u as default};
